var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【부록-003】 면담기록</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05：<color=#ffd34c>【付録-003】 面談記録</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【附錄-003】 面談記錄</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【附錄-003】 面談記錄</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เริ่มการทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข WR002M0011-05: <color=#ffd34c>[เอกสารแนบท้าย-003] บันทึกการสัมภาษณ์</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số. WR002M0011-05: <color=#ffd34c>[Phụ Lục-003] Hồ Sơ Phỏng Vấn</color>","SCN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【附录-003】 面谈记录</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. WR002M0011-05: <color=#ffd34c>【Anhang-003】 Interviewaufzeichnung</color>","FRA":"AEGIS 8\xA0PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN No. WR002M0011-05\xA0: <color=#ffd34c>【Annexe-003】 Rapport d'entretien</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"솔저 한소림, 관리국의 호출을 받아 지금 막 도착했다.","JPN":"ソルジャー ハネダ・ミズキ、管理局の要請により、ただいま馳せ参じた​。","ENG":"Soldier Han Sorim, reporting for duty under the Administration's summon.","TWN":"軍人韓蕭林，收到管理局的呼叫，準時到達。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하하, 경례는 안 하셔도 돼요.","JPN":"ハハ、敬礼は結構ですよ。","ENG":"Hah hah, there's no need to salute.","TWN":"哈哈，不用敬禮啦。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"긴장하지 말고 앉으세요. 그냥 절차에 따른 간단한 상담만 진행할 겁니다.","JPN":"リラックスしておかけ下さい。\\nほんの手続きです。簡単な面談だけで済みますので。","ENG":"Try to relax and sit down. We're just going to proceed with a short protocol interview.","TWN":"不要緊張，坐下吧。我只是按照流程，跟妳做些簡單的諮詢而已。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 저...... 입구에서 어떤 사람이 스미스 병장...... 아, 아니, 제 인형을 가져가던데요......","JPN":"ところで、その……入り口でスミス兵長を……\\nい、いや、お人形を取られてしまったんですが……","ENG":"But, uh... Someone took my Sergeant Smith... I-I mean, my doll at the entrance...","TWN":"但是那個……門口有人把史密斯兵長……啊，不對，是把我的娃娃拿走了……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 보안절차니까 이해해주세요. 다른 직원 분이 깔끔하게 소독해서 돌려드릴 겁니다.","JPN":"それも保安上の手続きでして、ご理解いただければ幸いです。\\n他の職員がきれいに消毒してお返しいたしますよ。","ENG":"Oh, it's just a security measure. The other employee will return it to you after having it sanitized.","TWN":"啊，那是安全流程，請理解一下。其他的員工消毒乾淨後會還給妳的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그보다 소림 양은 지금 가족들과 떨어져 지내고 있는데, 외롭진 않나요?","JPN":"それより、ハネダさんは今ご家族と離れて\\n暮らしておられますが、寂しかったりはしませんか？","ENG":"By the way, Sorim. I see that you're living away from your family. Don't you feel lonely at all?","TWN":"先不說這些了。蕭林妳會不會因為和家人分開住，所以感到寂寞呢？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"ENG":"A little bit...","TWN":"稍微有點……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"조금은......","JPN":"ちょっとだけ……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그래도 하림 언니가 있으니까, 괜찮다. 친구들도 많이 있고......","JPN":"で、でも、ウサギ隊長がいるから、平気だ。友達だってたくさんいるし……","ENG":"B-but it's okay since I have Harim with me. And I have a lot of friends...","TWN":"但、但是有夏琳姐姐陪著我，所以沒關係。而且我還交到了很多朋友……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니, 소림 양은 자신이...... 음...... 베테랑 군인이라고 주장하시는데요.","JPN":"そういえば、ハネダさんは……ご自身のことを、\\nその……ベテラン軍人だと主張なさっていますね。","ENG":"So, Sorim, you claim to be... um... a veteran soldier?","TWN":"這麼說來，蕭林小姐好像……呃……宣稱自己是老兵的樣子？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주장이 아니다! 사실을 이야기 한 것뿐이지.","JPN":"主張ではない！　事実を述べているだけだ。","ENG":"It's not a claim! I'm just stating facts.","TWN":"不是宣稱！我只不過陳述事實而已！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네, 알겠습니다. 그렇다고 치고요. 소림 양은 그럼 언제부터 군인이 되신 거죠?","JPN":"ええ、承知しました。そういうことにしておきましょう。\\nそれで、あなたはいつから軍人になられたのです？","ENG":"Yes, I understand. We'll say that's true. Then, Sorim, when did you join the military?","TWN":"是，我知道了，就當作是那樣吧。那蕭林小姐是從什麼時候開始從軍的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그건...... 그러니까......","JPN":"それは……その……","ENG":"That's... Uh...","TWN":"這……所以說……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어렸을 때...... 난 병원에서 살고 있었다.","JPN":"子供の頃……本官は病院で暮らしていた。","ENG":"When I was young... I was living at a hospital.","TWN":"小時候……我一直都住在醫院。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그때 난 거의 움직이지를 못해서...... 밖에 나가는 대신 아빠가 찍어온 사진들을 보면서 노는 게 일상이었다.","JPN":"あの頃、本官はほとんど体を動かせなかったから……父が外で撮ってきた\\n写真を眺めるのが日々の楽しみだったのだ。","ENG":"I could barely move back then... So instead of playing outside, I used to play with the photographs my dad brought me.","TWN":"那時候我幾乎不能動……沒辦法出去玩，所以看著爸爸拍的照片玩耍，就是我的日常。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 아버님이...... 종군 기자셨던 것 같군요.","JPN":"そういえば、お父様は……従軍記者をされていたとか。","ENG":"I see that you're father... was a war correspondent.","TWN":"說到這個，妳的父親似乎……是一名從軍記者吧。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};